import React, { useState } from 'react';
import { CustomTabsContainer, CustomTabsWrapContent, CustomTabsPanel, Accordion,} from './styles'

function Tabs(props: any) {
    const initialState = { selected: props.selected };
    const [state, setState] = useState(initialState);

    const handleSelection = (  event: any, index: number ):void => {
        event.preventDefault();
        setState({
            ...state,
            selected: index
        });
    }

    return (
        <>
            <CustomTabsPanel role="tablist">
                {props.children.map( (item:any, index:number) => {
                    return (
                        <li aria-controls={`tab-${index}`}  role="navigation" key={index}  onClick={ (e: any) => handleSelection(e, index) }>
                                {item.props.label}
                        </li>
                    );
                })}
            </CustomTabsPanel>
            <CustomTabsContainer>
                {props.children.map( (item:any, index:number) => {
                    return (
                        <>
                            <Accordion role="navigation" aria-controls={`tab-${index}`}  key={index} onClick={ (e: any) => handleSelection(e, index) }>{item.props.label}</Accordion>
                            <CustomTabsWrapContent aria-labelledby={`tab-${index}-content`} className={state.selected === index ? 'active' : ''}>
                                {props.children[state.selected]}
                            </CustomTabsWrapContent>
                        </>
                    );
                })}
             </CustomTabsContainer>
        </>
    );
}
export default Tabs;
